#!/usr/bin/env node

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

// Secure npm install script for CI/CD pipeline

function runSecureInstall() {
  try {
    // Verify package-lock.json exists for reproducible builds
    const lockFilePath = path.join(process.cwd(), 'package-lock.json');
    if (!fs.existsSync(lockFilePath)) {
      console.warn('Warning: package-lock.json not found. Creating one for reproducible builds.');
    }

    // Use npm ci for CI/CD environments - it's faster and more reliable
    // npm ci removes node_modules and installs from package-lock.json exactly
    // This prevents supply chain attacks from unexpected dependency updates
    console.log('Installing dependencies securely...');
    execSync('npm ci --ignore-scripts', {
      stdio: 'inherit',
      env: {
        ...process.env,
        NODE_ENV: process.env.NODE_ENV || 'production'
      }
    });

    // Audit dependencies for known vulnerabilities
    console.log('Auditing dependencies for security vulnerabilities...');
    try {
      execSync('npm audit --audit-level=moderate', {
        stdio: 'inherit'
      });
    } catch (auditError) {
      console.error('Security vulnerabilities found. Please review npm audit output.');
      process.exit(1);
    }

    // Only run postinstall scripts from trusted packages explicitly
    // Never run arbitrary postinstall scripts automatically
    console.log('Dependency installation complete.');
    console.log('Note: Postinstall scripts were disabled for security.');
    console.log('If specific postinstall tasks are needed, run them explicitly.');

  } catch (error) {
    console.error('Installation failed:', error.message);
    process.exit(1);
  }
}

runSecureInstall();